import{_ as a,o as l,c as i,ae as r}from"./chunks/framework.CyZiF_rV.js";const c=JSON.parse('{"title":"KSeF 2.0 - Руководство для Интеграторов","description":"","frontmatter":{},"headers":[],"relativePath":"ru/index.md","filePath":"ru/index.md"}'),t={name:"ru/index.md"};function n(o,e,h,s,f,p){return l(),i("div",null,[...e[0]||(e[0]=[r('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/README.md" target="_blank" rel="noreferrer">README.md</a></p></blockquote><h1 id="ksef-2-0-руководство-для-интеграторов" tabindex="-1"><strong>KSeF 2.0 - Руководство для Интеграторов</strong> <a class="header-anchor" href="#ksef-2-0-руководство-для-интеграторов" aria-label="Permalink to &quot;**KSeF 2.0 \\- Руководство для Интеграторов**&quot;">​</a></h1><p>22.12.2025</p><p>Данный документ представляет собой компендиум знаний для разработчиков, аналитиков и интеграторов систем, которые реализуют интеграцию с Национальной системой электронных счетов-фактур (KSeF) версии 2.0. Руководство сосредоточено на технических и практических аспектах, связанных с коммуникацией с API системы KSeF.</p><h2 id="введение-в-ksef-2-0" tabindex="-1">Введение в KSeF 2.0 <a class="header-anchor" href="#введение-в-ksef-2-0" aria-label="Permalink to &quot;Введение в KSeF 2.0&quot;">​</a></h2><p>Национальная система электронных счетов-фактур (KSeF) — это центральная телеинформационная система, предназначенная для выставления и получения структурированных счетов-фактур в электронном виде.</p><h2 id="содержание" tabindex="-1">Содержание <a class="header-anchor" href="#содержание" aria-label="Permalink to &quot;Содержание&quot;">​</a></h2><p>Руководство разделено на тематические разделы, соответствующие ключевым функциям и интеграционным областям в API KSeF:</p><ul><li><a href="./przeglad-kluczowych-zmian-ksef-api-2-0.html">Обзор ключевых изменений в KSeF 2.0</a></li><li><a href="./api-changelog.html">Журнал изменений</a></li><li>Аутентификация <ul><li><a href="./uwierzytelnianie.html">Получение доступа</a></li><li><a href="./auth/sesje.html">Управление сессиями</a></li></ul></li><li><a href="./uprawnienia.html">Разрешения</a></li><li><a href="./certyfikaty-KSeF.html">Сертификаты KSeF</a></li><li>Офлайн режимы <ul><li><a href="./tryby-offline.html">Офлайн режимы</a></li><li><a href="./offline/korekta-techniczna.html">Техническая коррекция</a></li></ul></li><li><a href="./kody-qr.html">QR-коды</a></li><li><a href="./sesja-interaktywna.html">Интерактивная сессия</a></li><li><a href="./sesja-wsadowa.html">Пакетная сессия</a></li><li>Получение счетов-фактур <ul><li><a href="./pobieranie-faktur/pobieranie-faktur.html">Получение счетов-фактур</a></li><li><a href="./pobieranie-faktur/przyrostowe-pobieranie-faktur.html">Инкрементальное получение счетов-фактур</a></li></ul></li><li><a href="./tokeny-ksef.html">Управление токенами KSeF</a></li><li><a href="./limity/limity.html">Лимиты</a></li><li><a href="./dane-testowe-scenariusze.html">Тестовые данные</a></li></ul><p>Для каждой области предусмотрено:</p><ul><li>детальное описание работы,</li><li>пример вызова на языках C# и Java,</li><li>связи со спецификацией <a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">OpenAPI</a> и кодом справочной библиотеки.</li></ul><p>Примеры кода, представленные в руководстве, подготовлены на основе официальных open source библиотек:</p><ul><li><a href="https://github.com/CIRFMF/ksef-client-csharp" target="_blank" rel="noreferrer">ksef-client-csharp</a> – библиотека на языке C#</li><li><a href="https://github.com/CIRFMF/ksef-client-java" target="_blank" rel="noreferrer">ksef-client-java</a> – библиотека на языке Java</li></ul><p>Обе библиотеки поддерживаются и развиваются командами Министерства финансов и предоставляются публично на условиях open source. Они обеспечивают полную поддержку функциональности API KSeF 2.0, включая обработку всех endpoints, моделей данных и примерных сценариев вызовов. Использование этих библиотек позволяет значительно упростить процесс интеграции и минимизирует риск неправильной интерпретации контрактов API.</p><h2 id="среды-системы" tabindex="-1">Среды системы <a class="header-anchor" href="#среды-системы" aria-label="Permalink to &quot;Среды системы&quot;">​</a></h2><p>Перечень сред KSeF API 2.0 описан в документе <a href="./srodowiska.html">Среды KSeF API 2.0</a></p>',16)])])}const m=a(t,[["render",n]]);export{c as __pageData,m as default};
